class Main {
  public static void main(String[] args) {
    System.out.println("Starting calculations...");

    try {
      // Dangerous code
      int answer = 100 / 0;
    } 
    catch (ArithmeticException e) {
      // The explosion was caught safely!
      System.out.println("Tried to divide by zero. Skipping!");
    }

    // The program survived!
    System.out.println("Calculations finished.");
  }
}

class Main {
